using namespace std;

int main() {
    int N;
    cin &gt;&gt; N;
    cin.ignore();
    vector&lt;string&gt; lines;
    for (int i = 0; i &lt; N; i++) {
        string line;
        getline(cin, line);
        lines.push_back(line);
    }

    // Define a regex pattern for the punctuation marks: apostrophe, period, comma, semicolon, colon
    regex punctuation_regex("[',.;:]");

    // Process lines in reverse order
    for (int i = N - 1; i &gt;= 0; i--) {
        // Remove punctuation using regex_replace
        string no_punct = regex_replace(lines[i], punctuation_regex, "");

        // Split the cleaned line into words using stringstream
        stringstream ss(no_punct);
        vector&lt;string&gt; words;
        string word;
        while (ss &gt;&gt; word) {
            words.push_back(word);
        }

        // Reverse the order of words and output them
        for (int j = words.size() - 1; j &gt;= 0; j--) {
            cout &lt;&lt; words[j];
            if (j &gt; 0)
                cout &lt;&lt; " ";
        }
        cout &lt;&lt; "\n";
    }

    return 0;
}
